class Solution(object):
    def removeAlmostEqualCharacters(self, word):
        ops = 0
        i = 1
        while i < len(word):
            diff = abs(ord(word[i]) - ord(word[i - 1]))
            if diff <= 1:
                ops += 1
                i += 2  # skip next character (we changed word[i] to fix this)
            else:
                i += 1
        return ops
